1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	const COMPONENT_PREMIUM = 25;
11	const COMPONENT_BLOCK_PREMIUM = 60;
12	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
13	
14	const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);
15	
16	function countByType(components: any[]): Record<string, number> {
17	  const counts: Record<string, number> = {};
18	  for (const c of components) {
19	    counts[c.type] = (counts[c.type] ?? 0) + 1;
20	  }
21	  return counts;
22	}
23	
24	function componentGroupPremium(count: number): number {
25	  return count === 3 ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
26	}
27	
28	function componentPremium(items: any[]): number {
29	  const components = items.filter(isComponent);
30	  const typeCounts = countByType(components);
31	  return Object.values(typeCounts).reduce(
32	    (sum, count) => sum + componentGroupPremium(count),
33	    0,
34	  );
35	}
36	
37	function itemPremium(item: any): number {
38	  const base = BASE_PREMIUMS[item.type] ?? 0;
39	  let surcharge = 0;
40	  if (item.cursed) surcharge += base * 0.5;
41	  if (item.enchantment >= 5) surcharge += base * 0.3;
42	  return base + surcharge;
43	}
44	
45	function policyBasePremium(items: any[]): number {
46	  const mainItems = items.filter((item: any) => !isComponent(item));
47	  const mainBase = mainItems.reduce(
48	    (sum: number, item: any) => sum + (BASE_PREMIUMS[item.type] ?? 0),
49	    0,
50	  );
51	  return mainBase + componentPremium(items);
52	}
53	
54	function calculateQuotePremium(items: any[]): number {
55	  const mainItems = items.filter((item: any) => !isComponent(item));
56	  const mainTotal = mainItems.reduce(
57	    (sum: number, item: any) => sum + itemPremium(item),
58	    0,
59	  );
60	  const componentTotal = componentPremium(items);
61	  const policyBase = policyBasePremium(items);
62	  const firstInsurance = policyBase * 0.1;
63	  return Math.ceil(mainTotal + componentTotal + firstInsurance + PROCESSING_FEE);
64	}
65	
66	export function processScenario(scenario: any): { results: { premium: number }[] } {
67	  const results = scenario.steps.map((step: any) => {
68	    const premium = calculateQuotePremium(step.items);
69	    return { premium };
70	  });
71	  return { results };
72	}
